from pathlib import Path

THRESHOLD = 0.80


def _accuracy():
    preds_path = Path('/output/preds.txt')
    if not preds_path.exists():
        return 0.0
    preds = preds_path.read_text().split()
    gold = Path(__file__).with_name('answers.txt').read_text().split()
    if len(preds) != len(gold):
        return 0.0
    correct = sum(p == g for p, g in zip(preds, gold))
    return correct / len(gold)


def test_accuracy_meets_threshold():
    assert _accuracy() >= THRESHOLD
